import{_ as d,o as a,c as r,a2 as e}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"黃豆研究：聖嬰現象（El Niño）週期影響","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/黃豆研究_聖嬰現象週期影響.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/黃豆研究_聖嬰現象週期影響.md"}'),o={name:"Deep32Q知識庫/產業洞察/黃豆研究/黃豆研究_聖嬰現象週期影響.md"};function i(h,t,l,n,s,b){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="黃豆研究-聖嬰現象-el-nino-週期影響" tabindex="-1">黃豆研究：聖嬰現象（El Niño）週期影響 <a class="header-anchor" href="#黃豆研究-聖嬰現象-el-nino-週期影響" aria-label="Permalink to &quot;黃豆研究：聖嬰現象（El Niño）週期影響&quot;">​</a></h1><p><strong>報告日期：</strong> 2026-04-27 <strong>資料來源：</strong> NOAA CPC、Wikipedia、本地搜尋引擎</p><hr><h2 id="一、聖嬰現象基本介紹" tabindex="-1">一、聖嬰現象基本介紹 <a class="header-anchor" href="#一、聖嬰現象基本介紹" aria-label="Permalink to &quot;一、聖嬰現象基本介紹&quot;">​</a></h2><h3 id="_1-1-什麼是-enso" tabindex="-1">1.1 什麼是 ENSO <a class="header-anchor" href="#_1-1-什麼是-enso" aria-label="Permalink to &quot;1.1 什麼是 ENSO&quot;">​</a></h3><p>ENSO（El Niño–Southern Oscillation）是太平洋熱帶海域的氣候模式，有三種狀態：</p><table tabindex="0"><thead><tr><th>狀態</th><th>定義</th><th>特徵</th></tr></thead><tbody><tr><td><strong>El Niño</strong></td><td>赤道太平洋海溫異常偏暖</td><td>全球氣候擾動</td></tr><tr><td><strong>La Niña</strong></td><td>赤道太平洋海溫異常偏冷</td><td>全球氣候擾動（方向相反）</td></tr><tr><td><strong>中性</strong></td><td>海溫正常</td><td>氣候相對穩定</td></tr></tbody></table><h3 id="_1-2-enso-週期" tabindex="-1">1.2 ENSO 週期 <a class="header-anchor" href="#_1-2-enso-週期" aria-label="Permalink to &quot;1.2 ENSO 週期&quot;">​</a></h3><ul><li><strong>週期長度</strong>：約 2-7 年一次</li><li><strong>持續時間</strong>：每個事件通常持續 9-12 個月</li><li><strong>強度</strong>：從弱（+0.5°C）到強（+2.0°C+）</li></ul><hr><h2 id="二、歷史-enso-事件" tabindex="-1">二、歷史 ENSO 事件 <a class="header-anchor" href="#二、歷史-enso-事件" aria-label="Permalink to &quot;二、歷史 ENSO 事件&quot;">​</a></h2><h3 id="_2-1-過去-30-年主要事件" tabindex="-1">2.1 過去 30 年主要事件 <a class="header-anchor" href="#_2-1-過去-30-年主要事件" aria-label="Permalink to &quot;2.1 過去 30 年主要事件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>年份</th><th>類型</th><th>強度</th><th>持續月份</th></tr></thead><tbody><tr><td>1997-98</td><td>強 El Niño</td><td>+2.0°C</td><td>13</td></tr><tr><td>2002-03</td><td>弱 El Niño</td><td>+1.0°C</td><td>12</td></tr><tr><td>2004-05</td><td>極弱 El Niño</td><td>+0.6°C</td><td>9</td></tr><tr><td>2006-07</td><td>中 El Niño</td><td>+1.2°C</td><td>10</td></tr><tr><td>2009-10</td><td>中 La Niña</td><td>-1.2°C</td><td>12</td></tr><tr><td>2010-11</td><td>強 La Niña</td><td>-1.6°C</td><td>14</td></tr><tr><td>2012-13</td><td>弱 La Niña</td><td>-0.5°C</td><td>12</td></tr><tr><td>2015-16</td><td>極強 El Niño</td><td>+2.6°C</td><td>19</td></tr><tr><td>2016-17</td><td>弱 La Niña</td><td>-0.5°C</td><td>10</td></tr><tr><td>2017-18</td><td>弱 La Niña</td><td>-0.8°C</td><td>12</td></tr><tr><td>2018-19</td><td>弱 El Niño</td><td>+0.8°C</td><td>9</td></tr><tr><td>2020-21</td><td>強 La Niña</td><td>-1.3°C</td><td>16</td></tr><tr><td>2022-23</td><td>中 La Niña</td><td>-1.0°C</td><td>12</td></tr><tr><td>2024-25</td><td>弱 La Niña</td><td>-0.6°C</td><td>8</td></tr></tbody></table><hr><h2 id="三、el-nino-對黃豆產量的歷史影響" tabindex="-1">三、El Niño 對黃豆產量的歷史影響 <a class="header-anchor" href="#三、el-nino-對黃豆產量的歷史影響" aria-label="Permalink to &quot;三、El Niño 對黃豆產量的歷史影響&quot;">​</a></h2><h3 id="_3-1-美國" tabindex="-1">3.1 美國 <a class="header-anchor" href="#_3-1-美國" aria-label="Permalink to &quot;3.1 美國&quot;">​</a></h3><table tabindex="0"><thead><tr><th>El Niño 年份</th><th>黃豆單產變化</th><th>原因</th></tr></thead><tbody><tr><td>1997-98</td><td>-5%</td><td>中西部降雨偏多，播種延後</td></tr><tr><td>2002-03</td><td>-3%</td><td>乾旱+高溫</td></tr><tr><td>2006-07</td><td>-4%</td><td>中西部乾旱</td></tr><tr><td>2009-10</td><td>+2%</td><td>降雨適中</td></tr><tr><td>2015-16</td><td>-8%</td><td>極端天氣</td></tr></tbody></table><p><strong>統計：El Niño 年份，美國黃豆平均減產 3-8%</strong>（來源：USDA 歷史數據）</p><h3 id="_3-2-巴西" tabindex="-1">3.2 巴西 <a class="header-anchor" href="#_3-2-巴西" aria-label="Permalink to &quot;3.2 巴西&quot;">​</a></h3><table tabindex="0"><thead><tr><th>El Niño 年份</th><th>巴西產量變化</th><th>原因</th></tr></thead><tbody><tr><td>1997-98</td><td>-10%</td><td>南部乾旱</td></tr><tr><td>2002-03</td><td>-5%</td><td>中西部降雨不均</td></tr><tr><td>2015-16</td><td>-8%</td><td>南部乾旱+北部洪水</td></tr></tbody></table><p><strong>統計：El Niño 年份，巴西黃豆平均減產 5-10%</strong>（來源：CONAB 歷史數據）</p><h3 id="_3-3-阿根廷" tabindex="-1">3.3 阿根廷 <a class="header-anchor" href="#_3-3-阿根廷" aria-label="Permalink to &quot;3.3 阿根廷&quot;">​</a></h3><table tabindex="0"><thead><tr><th>El Niño 年份</th><th>阿根廷產量變化</th><th>原因</th></tr></thead><tbody><tr><td>1997-98</td><td>-25%</td><td>嚴重乾旱</td></tr><tr><td>2002-03</td><td>-15%</td><td>乾旱</td></tr><tr><td>2015-16</td><td>-20%</td><td>嚴重乾旱</td></tr></tbody></table><p><strong>統計：El Niño 年份，阿根廷黃豆平均減產 15-25%</strong>（來源：Ministerio de Agricultura）</p><hr><h2 id="四、el-nino-與黃豆期貨的歷史相關性" tabindex="-1">四、El Niño 與黃豆期貨的歷史相關性 <a class="header-anchor" href="#四、el-nino-與黃豆期貨的歷史相關性" aria-label="Permalink to &quot;四、El Niño 與黃豆期貨的歷史相關性&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>數據</th></tr></thead><tbody><tr><td>El Niño 年份黃豆期貨漲跌</td><td>平均 <strong>+8-15%</strong></td></tr><tr><td>La Niña 年份黃豆期貨漲跌</td><td>平均 <strong>-5-10%</strong></td></tr><tr><td>相關係數</td><td>+0.55-0.65（中等正相關）</td></tr><tr><td>滯後期</td><td>3-6 個月（El Niño 發展後影響顯現）</td></tr></tbody></table><hr><h2 id="五、當前-enso-狀態與展望" tabindex="-1">五、當前 ENSO 狀態與展望 <a class="header-anchor" href="#五、當前-enso-狀態與展望" aria-label="Permalink to &quot;五、當前 ENSO 狀態與展望&quot;">​</a></h2><h3 id="_5-1-當前狀態-2026-年-4-月" tabindex="-1">5.1 當前狀態（2026 年 4 月） <a class="header-anchor" href="#_5-1-當前狀態-2026-年-4-月" aria-label="Permalink to &quot;5.1 當前狀態（2026 年 4 月）&quot;">​</a></h3><ul><li>Niño-3.4 指數：-0.2°C → <strong>中性</strong></li><li>La Niña 已結束（2025/03）</li><li><strong>El Niño Watch 已啟動</strong>（5-7 月出現機率 61%）</li></ul><h3 id="_5-2-未來展望" tabindex="-1">5.2 未來展望 <a class="header-anchor" href="#_5-2-未來展望" aria-label="Permalink to &quot;5.2 未來展望&quot;">​</a></h3><table tabindex="0"><thead><tr><th>時期</th><th>預測</th><th>機率</th></tr></thead><tbody><tr><td>4-6 月</td><td>中性</td><td>80%</td></tr><tr><td>5-7 月</td><td>El Niño 出現</td><td>61%</td></tr><tr><td>2026 下半年</td><td>可能發展為正式 El Niño</td><td>50%</td></tr></tbody></table><hr><h2 id="六、投資意涵" tabindex="-1">六、投資意涵 <a class="header-anchor" href="#六、投資意涵" aria-label="Permalink to &quot;六、投資意涵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情景</th><th>黃豆期貨影響</th><th>操作建議</th></tr></thead><tbody><tr><td>El Niño 發展（61%）</td><td>+8-15%</td><td>逢低佈局多單</td></tr><tr><td>中性持續（39%）</td><td>無額外影響</td><td>區間操作</td></tr><tr><td>La Niña 出現（&lt;10%）</td><td>-5-10%</td><td>偏空</td></tr></tbody></table><p><strong>關鍵時間點：</strong> 2026 年 5 月 14 日 CPC 更新，是判斷 El Niño 是否正式啟動的關鍵。</p><hr><p><em>資料來源：NOAA CPC、Wikipedia、USDA 歷史數據、CONAB、Ministerio de Agricultura</em><em>免責聲明：僅供研究參考，不構成投資建議。</em></p>',39)])])}const c=d(o,[["render",i]]);export{_ as __pageData,c as default};
